import chokidar from 'chokidar'
import { BrowserWindow } from 'electron'

let watcher: chokidar.FSWatcher | null = null

export function startWatching(dirPath: string): void {
  stopWatching()

  watcher = chokidar.watch(dirPath, {
    ignored: [
      /(^|[\/\\])\../, // dotfiles
      '**/node_modules/**',
      '**/out/**',
      '**/dist/**'
    ],
    persistent: true,
    ignoreInitial: true,
    depth: 10
  })

  const notify = (event: string, path: string): void => {
    const win = BrowserWindow.getFocusedWindow()
    win?.webContents.send('fs:change', { event, path })
  }

  watcher
    .on('add', (path) => notify('add', path))
    .on('unlink', (path) => notify('unlink', path))
    .on('addDir', (path) => notify('addDir', path))
    .on('unlinkDir', (path) => notify('unlinkDir', path))
    .on('change', (path) => notify('change', path))
}

export function stopWatching(): void {
  if (watcher) {
    watcher.close()
    watcher = null
  }
}

